import{_ as t,c as a,a0 as o,o as s}from"./chunks/framework.BQ6_cB1a.js";const h=JSON.parse('{"title":"Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"en-US/guide/faq.md","filePath":"en-US/guide/faq.md","lastUpdated":1723555172000}'),n={name:"en-US/guide/faq.md"};function i(r,e,l,d,c,p){return s(),a("div",null,e[0]||(e[0]=[o('<h1 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h1><details class="details custom-block"><summary>404 Error When Calling API</summary><p>Currently, not all OneBot standard APIs are supported. Please check if you have called an unsupported API.</p></details><details class="details custom-block"><summary>How to Use CQ Code?</summary><p>Change the message reporting format from message segments to CQ code.</p></details><details class="details custom-block"><summary>QR Code Cannot Be Scanned</summary><p>NapCat will automatically save the QR code to the directory, you can manually open the image to scan.</p><p>If you cannot access the local directory (e.g., purely command-line interface), you can copy the URL of the parsed QR code to a QR code generation website to regenerate the QR code, and then scan it with the QQ app on your phone.</p><p>Act quickly, as the QR code will expire!</p></details><details class="details custom-block"><summary>Voice/Video Sending Failed</summary><p>In this case, you need to manually configure the ffmpeg path. You can download ffmpeg <a href="./ffmpeg">here</a>.</p><p>Add the ffmpeg directory to the environment variable. If it still does not work, you can modify the NapCat startup script to add the FFMPEG_PATH variable, specifying the full path to the ffmpeg program. For example, on Windows, you can modify napcat.ps1, and add the following before the first line:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">FFMPEG_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;d:\\ffmpeg\\bin\\ffmpeg.exe&quot;</span></span></code></pre></div></details><details class="details custom-block"><summary>QQ Main Interface Appears on Windows Startup</summary><p>Try to start NapCat as an administrator. If it still fails, please report to the NapCat development group.</p></details><details class="details custom-block"><summary>Error Code v2:-1 and Similar Prompts</summary><p>This is a QQ issue and is normal, it does not affect usage.</p></details><details class="details custom-block"><summary>Login Prompt Shows &quot;Network Environment Unstable&quot; or &quot;Not on the Same Network&quot;</summary><p>If you encounter a network environment unstable/not on the same network prompt when scanning the code on the server, you can try logging in locally and then transferring the QQ configuration to the server&#39;s corresponding directory to overwrite it.</p><p>On Linux, the QQ configuration directory is located at <code>~/.config/QQ</code>; on Windows, it is generally in the <strong>QQ folder under Documents</strong> (by default, <code>&lt;system drive&gt;:\\Users (user)\\Documents\\Tencent Files</code>). You can check the specific location by opening QQ settings and going to the &quot;Storage Management&quot; section.</p><p>Alternatively, use a VPN on your phone to connect to the server network so that your phone and the server are on the same network, which can also resolve this issue.</p></details><details class="details custom-block"><summary>&quot;sqlite3 is not a win32 application&quot; Error on Windows</summary><p>When running, if you encounter <code>node_sqlite3.node is not a valid Win32 application</code>, please check whether you have downloaded the Windows version of NapCatQQ and whether you have installed the 64-bit version of QQ.</p></details><details class="details custom-block"><summary>Unknown Crash</summary><p>Due to the use of Native Hook in the new version, if your NapCatQQ crashes, try deleting <code>MoeHoo-xxxx.node</code>.</p></details><details class="details custom-block"><summary>&quot;MH Hook Hk sub XXXX Error&quot; Crash Error</summary><p>If you have previously used LLOneBot and used Liteloader&#39;s one-click package or a DLL to skip verification, you should delete the one-click package and related DLLs, or completely clean and reinstall QQNT.</p></details>',11)]))}const m=t(n,[["render",i]]);export{h as __pageData,m as default};
